### Interactive Exploration: Latent Variable Threshold {.unnumbered}

::: {.callout-tip}
## Try It: Shift the Latent Distribution

There is no η slider here: η is computed for you as η = α + β·X = 0.5 + β·X. Start by dragging the **β (effect of X)** slider, then the **X value** slider, and watch the whole latent distribution slide relative to the threshold at zero. The shaded area above zero equals the predicted probability P(Y=1). Use the **Link function** radio (Logit / Probit) to swap the latent error distribution, and **Reset** to return to the defaults. We simulate the latent density in the browser because the point is to *see* the unobserved continuum and move it with a known truth — a single real dataset never reveals y\* directly, so only a counterfactual, slider-driven curve can show how shifting η redistributes mass across the threshold.
:::

```{ojs}
//| echo: false
import { ber640 as latent_ber640, plotDefaults as latent_plotDefaults, themeColors as latent_themeColors, onThemeChange as latent_onThemeChange, sigmoid as latent_sigmoid, seq as latent_seq, formatCoef as latent_formatCoef, withAlpha as latent_withAlpha, srSummary as latent_srSummary, resetControls as latent_resetControls } from "../ojs/shared.js"
```

```{ojs}
//| echo: false
latent_theme = latent_themeColors()
```

```{ojs}
//| echo: false
latent_pill = (label, value, tone = "") => html`<span class="ojs-readout ${tone ? "ojs-readout-" + tone : ""}"><span class="ojs-readout-label">${label}</span><span class="ojs-readout-value">${value}</span></span>`
```

```{ojs}
//| echo: false
viewof latent_beta = Inputs.range([-3, 3], {label: "β (effect of X)", value: 1.0, step: 0.1})
```

```{ojs}
//| echo: false
viewof latent_xval = Inputs.range([-2, 2], {label: "X value", value: 0.5, step: 0.1})
```

```{ojs}
//| echo: false
viewof latent_link = Inputs.radio(["Logit", "Probit"], {label: "Link function", value: "Logit"})
```

```{ojs}
//| echo: false

latent_alpha = 0.5
latent_eta = latent_alpha + latent_beta * latent_xval

latent_scale_logistic = 1

latent_logisticDensity = function(x, mu, s) {
  const z = -(x - mu) / s;
  const ez = Math.exp(z);
  return ez / (s * Math.pow(1 + ez, 2));
}

latent_normalDensity = function(x, mu, sigma) {
  const z = (x - mu) / sigma;
  return Math.exp(-0.5 * z * z) / (sigma * Math.sqrt(2 * Math.PI));
}

latent_normalCDF = function(x) {
  const a1 = 0.254829592, a2 = -0.284496736, a3 = 1.421413741;
  const a4 = -1.453152027, a5 = 1.061405429, p = 0.3275911;
  const sign = x < 0 ? -1 : 1;
  const z = Math.abs(x) / Math.sqrt(2);
  const t = 1.0 / (1.0 + p * z);
  const y = 1.0 - (((((a5 * t + a4) * t) + a3) * t + a2) * t + a1) * t * Math.exp(-z * z);
  return 0.5 * (1.0 + sign * y);
}

latent_prob_logit = latent_sigmoid(latent_eta)
latent_prob_probit = latent_normalCDF(latent_eta)
latent_prob = latent_link === "Logit" ? latent_prob_logit : latent_prob_probit

// Scale-matched probit: the logistic latent SD is pi/sqrt(3) ~ 1.81 vs 1 for the
// probit, so Lambda(eta) and Phi(eta) at the SAME eta are NOT comparable. The
// textbook rule of thumb beta_logit ~ 1.7 * beta_probit (equivalently, divide the
// logit linear predictor by 1.7 to land on the probit scale) makes them agree
// closely over the practical middle range. Used only to show that rescaling
// reduces the difference; it is not an exact identity.
latent_scaleConst = 1.7
latent_prob_probit_matched = latent_normalCDF(latent_eta / latent_scaleConst)
latent_matchGapPt = Math.abs(latent_prob_logit - latent_prob_probit_matched) * 100

latent_domainPad = latent_link === "Logit" ? 4.5 : 3.5
latent_xDomain = [
  Math.min(-6, latent_eta - latent_domainPad),
  Math.max(6, latent_eta + latent_domainPad)
]
latent_xRange = latent_seq(latent_xDomain[0], latent_xDomain[1], 300)
latent_clamp = (x, lo, hi) => Math.max(lo, Math.min(hi, x))
latent_y0LabelX = latent_clamp(Math.min(-1.5, latent_eta - 1.5), latent_xDomain[0] + 0.8, -0.35)
latent_y1LabelX = latent_clamp(Math.max(1.5, latent_eta + 1.5), 0.35, latent_xDomain[1] - 0.8)

latent_densityData = latent_xRange.map(x => ({
  x: x,
  y: latent_link === "Logit"
    ? latent_logisticDensity(x, latent_eta, latent_scale_logistic)
    : latent_normalDensity(x, latent_eta, 1),
  region: x >= 0 ? "P(Y=1)" : "P(Y=0)"
}))

latent_peakY = Math.max(...latent_densityData.map(d => d.y))
```

