  ${latent_pill("Probit P(Y=1)", (latent_prob_probit * 100).toFixed(1) + "%", latent_link === "Probit" ? "info" : "")}
  ${latent_pill("Probit @ η÷1.7", (latent_prob_probit_matched * 100).toFixed(1) + "%", "good")}
